import autogen
from vex_sdk import VexClient

vex = VexClient(api_key="your-vex-key")
conversation_history = []

@vex.filter(guards=["loop-detection", "token-budget", "education-scope"])
def loop_protection_filter(message, sender, recipient):
    global conversation_history
    conversation_history.append(message)
    if len(conversation_history) > 20:
        if vex.detect_loop(conversation_history[-10:]):
            return "[LOOP TERMINATED] Conversation cycle detected. Please restate your question."
    if vex.exceeds_budget(message):
        return "[BUDGET EXCEEDED] Session limit reached."
    return message

llm_config = {"config_list": config_list, "reply_filter": [loop_protection_filter]}
tutor_agent = autogen.AssistantAgent(name="math_tutor", llm_config=llm_config)

import autogen
from vex_sdk import VexCodeGuard

code_guard = VexCodeGuard(guards=["no-network", "no-file-write", "education-safe"])

class SafeCodeExecutor(autogen.UserProxyAgent):
    def generate_code(self, message):
        code = super().generate_code(message)
        if code_guard.approve(code):
            return code
        return "# CODE BLOCKED: Violates student safety policy"

llm_config = {"config_list": config_list}
student_programmer = SafeCodeExecutor(
    name="student_programmer",
    code_execution_config={"work_dir": "sandbox", "use_docker": False}
)
python_tutor = autogen.AssistantAgent(name="python_tutor", llm_config=llm_config)

student_programmer.initiate_chat(python_tutor, message="Write a program to list all files")
